class Solution:
  def solve(self, nums: list[int]) -> bool:
    st = []
    for i in range(len(nums)):
      if len(st) > 0 and nums[i] < st[-1]:
        while len(st) > 0 and st[-1] > nums[i]:
          st.pop()
      st.append(nums[i])
    return st == sorted(nums, reverse=True)


